//! # E8-Lattice Quantizer — the optimal 8-D vector quantizer.
//!
//! E_8 is the optimal lattice quantizer in dimension 8: its normalized
//! second moment G(E_8) ≈ 0.0717 is the lowest known of any 8-D lattice,
//! versus the cubic integer lattice ℤ⁸ with G(ℤ⁸) = 1/12 ≈ 0.08333. That
//! is a ~14% lower mean-squared quantization error per sample for equal
//! cell density — denser, more isotropic Voronoi cells. E_8 is also the
//! densest 8-D packing (kissing number 240), so a quantized cell has 240
//! equidistant nearest neighbours: the 240 root directions.
//!
//! This module gives the runtime the Conway–Sloane O(n) nearest-point
//! decoder for E_8 and exposes the 240-root shell as the set of
//! nearest-neighbour quantization steps.
//!
//! ## Lean SSOT (the contract this code owes)
//!
//! The lattice itself, its 240 roots, and the certificate that those 240
//! vectors really are the E_8 root system (closure under the Weyl group)
//! are proven in `open-source/gnosis-math/Gnosis/E8Lattice.lean`:
//!
//!   * `Gnosis.E8Lattice.e8_root_count`     — exactly 240 roots.
//!   * `Gnosis.E8Lattice.e8_norm_homogeneous` — every root has norm² = 8
//!                                              (scaled model).
//!   * `Gnosis.E8Lattice.reflection_closure`  — the 240 are CLOSED under
//!         the simple reflections ⇒ they ARE the E_8 root system, not 240
//!         arbitrary norm-8 vectors. This is the load-bearing certificate.
//!   * `Gnosis.OrientationE8Bridge` / `ADEMcKayCorrespondence` — the
//!         orientation→spin→2I→E_8 seam (|2I| = 120, 600-cell = optimal
//!         SO(3) sampling) relevant to the normals/orientation angle.
//!
//! This file does NOT re-prove those facts; it pins them as compile-time
//! contract constants ([`THEOREM_ROOT_COUNT`], [`THEOREM_ROOT_NORMSQ`],
//! [`THEOREM_REFLECTION_CLOSURE`]) and the tests assert the runtime shell
//! matches the Lean root count / norms.
//!
//! ## The scaling map (Lean integer model ⇄ standard E_8)
//!
//! Standard E_8 (Conway–Sloane) = D8 ∪ (D8 + (½,…,½)), root norm² = 2.
//! The Lean module scales **every coordinate by 2** so the half-integers
//! become integers (see E8Lattice.lean header):
//!
//!     standard point  s ∈ E_8      ↦   Lean point  L = 2·s  ∈ ℤ⁸
//!     standard root   norm² = 2     ↦   Lean root   norm² = 8
//!
//! So:
//!   * a `family1` Lean root = two entries ±2, rest 0   (norm² 8);
//!   * a `family2` Lean root = all ±1, even # of −1      (norm² 8).
//!
//! Our decoder works in **standard** coordinates (round-to-D8 is cleanest
//! there), then multiplies the result by 2 to return a point of the Lean
//! scaled lattice. The output of [`nearest_e8`] is therefore always a Lean
//! E8 lattice point (`Gnosis.E8Lattice`-consistent), and the 240
//! nearest-neighbour steps from any lattice point are exactly the Lean
//! `e8Roots` (see [`e8_root_shell`]).

#![allow(dead_code)]

// ── Lean contract constants (theorem IDs, not re-proofs) ────────────────

/// `Gnosis.E8Lattice.e8_root_count` — E_8 has exactly 240 roots.
pub const THEOREM_ROOT_COUNT: usize = 240;
/// `Gnosis.E8Lattice.e8_norm_homogeneous` — every root has norm² = 8 in
/// the scaled integer model.
pub const THEOREM_ROOT_NORMSQ: i64 = 8;
/// `Gnosis.E8Lattice.reflection_closure` — the load-bearing certificate
/// that the 240 vectors are closed under the Weyl group, i.e. are the E_8
/// root system. The shell this module returns must equal that set.
pub const THEOREM_REFLECTION_CLOSURE: &str = "Gnosis.E8Lattice.reflection_closure";

/// Normalized second moment of E_8 (the optimal 8-D lattice quantizer).
/// G(E_8) = 929569 / (12960000) ≈ 0.0716821. This is the headline: the
/// theoretical floor we expect the empirical estimator to approach.
pub const G_E8: f64 = 0.071682_2;
/// Normalized second moment of the cubic lattice ℤ⁸: G = 1/12.
pub const G_Z8: f64 = 1.0 / 12.0;

// ── D8 / E8 nearest-point decoding (Conway–Sloane, standard coords) ─────

/// Round a real to the nearest integer, ties away from zero. Returns the
/// rounded value and the signed rounding residual `x - round(x)` (used to
/// find the "worst-rounded" coordinate for the D8 parity flip).
#[inline]
fn round_residual(x: f64) -> (i64, f64) {
    let r = x.round(); // ties to even in Rust; fine, we track the residual
    (r as i64, x - r)
}

/// Nearest point of **D_n** (the checkerboard lattice: integer vectors
/// with even coordinate sum) to `x`, in standard coordinates.
///
/// Conway–Sloane Algorithm: round each coordinate; if the resulting sum is
/// odd, flip (±1) the single coordinate whose rounding residual was the
/// largest in magnitude — that is the cheapest way to fix parity. O(n).
fn nearest_d8(x: &[f64; 8]) -> [i64; 8] {
    let mut out = [0i64; 8];
    let mut sum = 0i64;
    let mut worst_idx = 0usize;
    let mut worst_mag = -1.0f64;
    let mut worst_resid = 0.0f64;
    for i in 0..8 {
        let (r, resid) = round_residual(x[i]);
        out[i] = r;
        sum += r;
        let m = resid.abs();
        if m > worst_mag {
            worst_mag = m;
            worst_idx = i;
            worst_resid = resid;
        }
    }
    if sum % 2 != 0 {
        // Flip the worst-rounded coordinate toward where it "wanted" to go.
        // If residual > 0 we rounded down too far → bump up; else bump down.
        if worst_resid > 0.0 {
            out[worst_idx] += 1;
        } else {
            out[worst_idx] -= 1;
        }
    }
    out
}

/// Squared Euclidean distance between a real vector and an integer point
/// (both in standard coordinates).
#[inline]
fn dist_sq(x: &[f64; 8], p: &[i64; 8]) -> f64 {
    let mut d = 0.0f64;
    for i in 0..8 {
        let e = x[i] - p[i] as f64;
        d += e * e;
    }
    d
}

/// Nearest point of **standard E_8** = D8 ∪ (D8 + (½,…,½)) to `x`, in
/// standard coordinates, returned as a `[f64;8]` (the glue coset has
/// half-integer entries). O(n) Conway–Sloane: decode D8, decode the
/// shifted-by-½ coset, return whichever is closer.
fn nearest_e8_standard(x: &[f64; 8]) -> [f64; 8] {
    // Coset 0: D8 itself.
    let d0 = nearest_d8(x);
    let mut p0 = [0.0f64; 8];
    for i in 0..8 {
        p0[i] = d0[i] as f64;
    }
    let dist0 = dist_sq(x, &d0);

    // Coset 1: D8 + (½,…,½). Shift by −½, decode D8, shift back by +½.
    let mut xs = [0.0f64; 8];
    for i in 0..8 {
        xs[i] = x[i] - 0.5;
    }
    let d1 = nearest_d8(&xs);
    let mut p1 = [0.0f64; 8];
    let mut dist1 = 0.0f64;
    for i in 0..8 {
        p1[i] = d1[i] as f64 + 0.5;
        let e = x[i] - p1[i];
        dist1 += e * e;
    }

    if dist0 <= dist1 {
        p0
    } else {
        p1
    }
}

/// **Nearest point of standard E_8** to a real input `x`, returned in standard
/// coordinates (the glue coset has half-integer entries). Public wrapper around
/// the Conway–Sloane decoder for callers that need the standard-coordinate
/// nearest point directly (e.g. per-tile lattice refinement at a matched cell
/// volume), without the Lean ×2 integer rescale.
#[inline]
pub fn nearest_e8_standard_point(x: &[f64; 8]) -> [f64; 8] {
    nearest_e8_standard(x)
}

/// **Nearest E_8 lattice point** to a real input `x`, returned in the
/// **Lean scaled integer model** (coordinates = 2 × standard E_8 coords,
/// hence always integers). The returned point is a genuine
/// `Gnosis.E8Lattice` lattice point.
///
/// O(n) Conway–Sloane: decode standard E_8 (D8 ∪ glue coset), scale by 2.
/// The caller's `x` is in **Lean (×2) coordinates**; we divide by 2 to
/// enter standard space, decode, then multiply the integer-or-half-integer
/// standard point by 2 to land back on the integer Lean lattice.
pub fn nearest_e8(x: [f64; 8]) -> [i64; 8] {
    // Enter standard coordinates: standard = lean / 2.
    let mut xs = [0.0f64; 8];
    for i in 0..8 {
        xs[i] = x[i] * 0.5;
    }
    let s = nearest_e8_standard(&xs);
    // Back to Lean model: lean = 2 * standard. standard entries are integers
    // (coset 0) or half-integers (coset 1); ×2 makes both integers exactly.
    let mut out = [0i64; 8];
    for i in 0..8 {
        out[i] = (s[i] * 2.0).round() as i64;
    }
    out
}

/// Squared norm of a Lean-model integer vector.
#[inline]
fn norm_sq_i(v: &[i64; 8]) -> i64 {
    v.iter().map(|&c| c * c).sum()
}

/// True iff `v` (Lean ×2 coordinates) is a point of the E_8 lattice.
///
/// In standard coords s = v/2, E_8 = D8 ∪ (D8+½). Membership test in the
/// scaled model:
///   * all entries same parity (all even ⇒ standard integers = D8 candidate,
///     or all odd ⇒ standard half-integers = glue candidate); AND
///   * for the all-even case: standard coords integer with even sum
///     (D8) — sum of v ≡ 0 mod 4;
///   * for the all-odd case: standard half-integers with the D8 parity on
///     the shifted lattice — sum of (v−1)/2 even, i.e. (Σv − 8)/2 even.
/// We verify directly by re-decoding: a lattice point is its own nearest
/// neighbour (round-trip identity), which is the cleanest exact test.
pub fn is_e8_point(v: &[i64; 8]) -> bool {
    let xf = [
        v[0] as f64,
        v[1] as f64,
        v[2] as f64,
        v[3] as f64,
        v[4] as f64,
        v[5] as f64,
        v[6] as f64,
        v[7] as f64,
    ];
    nearest_e8(xf) == *v
}

// ── The 240-root shell (nearest-neighbour quantization steps) ───────────

/// The 240 E_8 roots in the Lean scaled integer model, generated to be
/// byte-identical with `Gnosis.E8Lattice.e8Roots` (family1 ++ family2).
/// These are the minimal-norm (norm² = 8) lattice vectors — the 240
/// equidistant nearest neighbours of any lattice cell, i.e. the
/// nearest-neighbour quantization steps / Voronoi-relevant directions.
pub fn e8_root_shell() -> [[i64; 8]; 240] {
    let mut roots = [[0i64; 8]; 240];
    let mut idx = 0usize;
    // family1: two entries ±2, rest 0 — 112 roots. Same nesting order as
    // E8Lattice.family1 (pairs i<j, then si∈{−2,2}, then sj∈{−2,2}).
    for i in 0..8 {
        for j in (i + 1)..8 {
            for &si in &[-2i64, 2] {
                for &sj in &[-2i64, 2] {
                    let mut v = [0i64; 8];
                    v[i] = si;
                    v[j] = sj;
                    roots[idx] = v;
                    idx += 1;
                }
            }
        }
    }
    // family2: all entries ±1 with an EVEN number of −1 — 128 roots.
    // E8Lattice.family2 enumerates signs 8 (LSB-first ::-cons) filtered to
    // even negCount; the set is identical regardless of enumeration order.
    for bits in 0u32..256 {
        if (bits.count_ones() % 2) == 0 {
            let mut v = [0i64; 8];
            for k in 0..8 {
                v[k] = if (bits >> k) & 1 == 1 { -1 } else { 1 };
            }
            roots[idx] = v;
            idx += 1;
        }
    }
    debug_assert_eq!(idx, 240);
    roots
}

/// True iff `step` is one of the 240 root steps (a single nearest-neighbour
/// move on the lattice). Used by the E8-neighbour admission sieve.
pub fn is_root_step(step: &[i64; 8]) -> bool {
    norm_sq_i(step) == THEOREM_ROOT_NORMSQ && {
        // norm²=8 in the scaled model is exactly the root shell (the
        // minimal vectors). reflection_closure guarantees this set is the
        // E_8 root system. A norm-8 lattice vector must be a root.
        is_e8_point(step)
    }
}

/// True iff lattice points `a` and `b` are E_8 nearest neighbours: their
/// difference is one of the 240 roots (a single root-step apart).
pub fn is_neighbor(a: &[i64; 8], b: &[i64; 8]) -> bool {
    let mut d = [0i64; 8];
    for i in 0..8 {
        d[i] = a[i] - b[i];
    }
    is_root_step(&d)
}

// ── Quantization error / normalized second moment ──────────────────────

/// Squared quantization error of input `x` under the E_8 quantizer (in
/// Lean ×2 coordinates): ‖x − Q(x)‖² where Q = [`nearest_e8`].
pub fn quantization_error_sq(x: [f64; 8]) -> f64 {
    let q = nearest_e8(x);
    let mut d = 0.0f64;
    for i in 0..8 {
        let e = x[i] - q[i] as f64;
        d += e * e;
    }
    d
}

/// RMS quantization error of input `x` (sqrt of mean per-coordinate
/// squared error) under the E_8 quantizer, in Lean ×2 coordinates.
pub fn quantization_error(x: [f64; 8]) -> f64 {
    (quantization_error_sq(x) / 8.0).sqrt()
}

/// Empirical **normalized second moment** estimator for a quantizer, in
/// **standard** coordinates so the result is directly comparable to the
/// dimensionless lattice constant G.
///
/// G = E[‖x − Q(x)‖²] / (n · V^(2/n)) where V is the Voronoi-cell volume
/// (= lattice fundamental-domain volume). For standard E_8, V = 1
/// (det = 1, unimodular). For ℤ⁸, V = 1 as well. So with both lattices at
/// unit cell volume, G = E[‖e‖²]/n and the ratio G_E8/G_Z8 = the raw MSE
/// ratio — which is what we report.
///
/// `samples` are uniform points; this returns mean ‖e‖²/n.
fn nsm_estimate_standard<F>(samples: &[[f64; 8]], mut quant_err_sq_std: F) -> f64
where
    F: FnMut(&[f64; 8]) -> f64,
{
    if samples.is_empty() {
        return 0.0;
    }
    let mut acc = 0.0f64;
    for s in samples {
        acc += quant_err_sq_std(s);
    }
    acc / (samples.len() as f64 * 8.0)
}

/// Standard-coordinate squared error for **E_8** (V = 1).
pub fn e8_err_sq_standard(x: &[f64; 8]) -> f64 {
    let s = nearest_e8_standard(x);
    let mut d = 0.0f64;
    for i in 0..8 {
        let e = x[i] - s[i];
        d += e * e;
    }
    d
}

/// Standard-coordinate squared error for **ℤ⁸** (cubic, V = 1): just round.
pub fn z8_err_sq_standard(x: &[f64; 8]) -> f64 {
    let mut d = 0.0f64;
    for i in 0..8 {
        let e = x[i] - x[i].round();
        d += e * e;
    }
    d
}

/// Empirical normalized second moment of the **E_8** quantizer over the
/// given uniform samples (both lattices scaled to unit cell volume).
pub fn normalized_second_moment_e8(samples: &[[f64; 8]]) -> f64 {
    nsm_estimate_standard(samples, e8_err_sq_standard)
}

/// Empirical normalized second moment of the **ℤ⁸** (cubic) quantizer.
pub fn normalized_second_moment_z8(samples: &[[f64; 8]]) -> f64 {
    nsm_estimate_standard(samples, z8_err_sq_standard)
}

// ── Deterministic uniform sampler (no rand dep) ─────────────────────────

/// Tiny SplitMix64 — deterministic, dependency-free uniform samples in a
/// box large enough that boundary effects are negligible. Used by tests
/// and the bench so results are reproducible.
pub struct SplitMix64 {
    state: u64,
}

impl SplitMix64 {
    pub fn new(seed: u64) -> Self {
        Self { state: seed }
    }
    #[inline]
    fn next_u64(&mut self) -> u64 {
        self.state = self.state.wrapping_add(0x9E37_79B9_7F4A_7C15);
        let mut z = self.state;
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^ (z >> 31)
    }
    /// Uniform f64 in [-half, half).
    #[inline]
    pub fn next_in(&mut self, half: f64) -> f64 {
        let u = (self.next_u64() >> 11) as f64 / (1u64 << 53) as f64; // [0,1)
        (u - 0.5) * 2.0 * half
    }
    /// A uniform 8-vector in the box [-half, half)^8 (standard coords).
    pub fn next_vec8(&mut self, half: f64) -> [f64; 8] {
        let mut v = [0.0f64; 8];
        for c in v.iter_mut() {
            *c = self.next_in(half);
        }
        v
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── nearest_e8 correctness ──────────────────────────────────────────

    #[test]
    fn nearest_e8_returns_a_lattice_point() {
        let mut rng = SplitMix64::new(0xE8E8_E8E8);
        for _ in 0..2000 {
            // Lean-coordinate inputs (×2 space): sample standard, scale ×2.
            let s = rng.next_vec8(5.0);
            let x = [
                s[0] * 2.0,
                s[1] * 2.0,
                s[2] * 2.0,
                s[3] * 2.0,
                s[4] * 2.0,
                s[5] * 2.0,
                s[6] * 2.0,
                s[7] * 2.0,
            ];
            let q = nearest_e8(x);
            assert!(
                is_e8_point(&q),
                "nearest_e8 must return an E8 lattice point: {q:?}"
            );
        }
    }

    #[test]
    fn lattice_point_round_trips_to_itself() {
        // Every root is a lattice point; quantizing it returns itself.
        for r in e8_root_shell().iter() {
            let xf = [
                r[0] as f64,
                r[1] as f64,
                r[2] as f64,
                r[3] as f64,
                r[4] as f64,
                r[5] as f64,
                r[6] as f64,
                r[7] as f64,
            ];
            assert_eq!(nearest_e8(xf), *r, "root must quantize to itself: {r:?}");
        }
        // The origin and a glue-coset point too. Glue point in Lean coords:
        // standard (½,…,½) ↦ ×2 ↦ (1,1,1,1,1,1,1,1), an E8 point.
        assert_eq!(nearest_e8([0.0; 8]), [0i64; 8]);
        assert_eq!(nearest_e8([1.0; 8]), [1i64; 8]);
        assert!(is_e8_point(&[1i64; 8]));
    }

    // ── shell matches the Lean root system ──────────────────────────────

    #[test]
    fn shell_matches_lean_root_count_and_norms() {
        let shell = e8_root_shell();
        assert_eq!(
            shell.len(),
            THEOREM_ROOT_COUNT,
            "Gnosis.E8Lattice.e8_root_count"
        );
        // Every root has norm² = 8 (e8_norm_homogeneous).
        for r in shell.iter() {
            assert_eq!(
                norm_sq_i(r),
                THEOREM_ROOT_NORMSQ,
                "e8_norm_homogeneous: {r:?}"
            );
        }
        // 112 family1 (two ±2) + 128 family2 (all ±1, even # of −1).
        let fam1 = shell
            .iter()
            .filter(|r| r.iter().any(|&c| c.abs() == 2))
            .count();
        let fam2 = shell
            .iter()
            .filter(|r| r.iter().all(|&c| c.abs() == 1))
            .count();
        assert_eq!(fam1, 112, "family1_count");
        assert_eq!(fam2, 128, "family2_count");
        // All 240 distinct.
        let mut set = std::collections::HashSet::new();
        for r in shell.iter() {
            assert!(set.insert(*r), "roots must be distinct: {r:?}");
        }
        assert_eq!(set.len(), 240);
    }

    #[test]
    fn every_shell_root_is_a_lattice_point_and_root_step() {
        for r in e8_root_shell().iter() {
            assert!(is_e8_point(r), "root is a lattice point: {r:?}");
            assert!(is_root_step(r), "root is a root-step: {r:?}");
            assert!(
                is_neighbor(r, &[0i64; 8]),
                "root neighbours the origin: {r:?}"
            );
        }
    }

    #[test]
    fn non_root_lattice_vectors_are_not_root_steps() {
        // 2*root has norm² 32, a lattice point but NOT a nearest neighbour.
        let r = e8_root_shell()[0];
        let two_r = [
            r[0] * 2,
            r[1] * 2,
            r[2] * 2,
            r[3] * 2,
            r[4] * 2,
            r[5] * 2,
            r[6] * 2,
            r[7] * 2,
        ];
        assert!(is_e8_point(&two_r));
        assert!(!is_root_step(&two_r), "2·root is not a unit root-step");
    }

    // ── E8 beats cubic on quantization error ────────────────────────────

    #[test]
    fn e8_quantization_error_below_cubic_on_random_points() {
        let mut rng = SplitMix64::new(0x1234_5678_9ABC_DEF0);
        const N: usize = 20_000;
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            samples.push(rng.next_vec8(8.0)); // standard coords, big box
        }
        let g_e8 = normalized_second_moment_e8(&samples);
        let g_z8 = normalized_second_moment_z8(&samples);
        assert!(
            g_e8 < g_z8,
            "E8 NSM ({g_e8:.6}) must be below cubic ℤ⁸ NSM ({g_z8:.6})"
        );
        // Sanity: ℤ⁸ should be near its exact constant 1/12 ≈ 0.0833.
        assert!((g_z8 - G_Z8).abs() < 0.005, "ℤ⁸ NSM ≈ 1/12, got {g_z8:.6}");
        // E8 should be near its constant 0.0717 (loose band for finite N).
        assert!(
            (g_e8 - G_E8).abs() < 0.006,
            "E8 NSM ≈ 0.0717, got {g_e8:.6}"
        );
    }

    // ── empirical NSM bench (printed; cold vs warm) ─────────────────────

    #[test]
    fn bench_nsm_e8_vs_cubic_ratio() {
        const N: usize = 200_000;
        let mut rng = SplitMix64::new(0xC0FF_EE00_1234_5678);
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            samples.push(rng.next_vec8(16.0));
        }
        // COLD: first pass (caches cold, branch predictor unwarmed).
        let t0 = std::time::Instant::now();
        let g_e8_cold = normalized_second_moment_e8(&samples);
        let cold_e8 = t0.elapsed();
        let t1 = std::time::Instant::now();
        let g_z8_cold = normalized_second_moment_z8(&samples);
        let cold_z8 = t1.elapsed();

        // WARM: re-run on the same samples.
        let t2 = std::time::Instant::now();
        let g_e8_warm = normalized_second_moment_e8(&samples);
        let warm_e8 = t2.elapsed();
        let t3 = std::time::Instant::now();
        let g_z8_warm = normalized_second_moment_z8(&samples);
        let warm_z8 = t3.elapsed();

        let ratio_cold = g_e8_cold / g_z8_cold;
        let ratio_warm = g_e8_warm / g_z8_warm;
        let pct_better = (1.0 - ratio_warm) * 100.0;
        let per_pt_cold_ns = cold_e8.as_nanos() as f64 / N as f64;
        let per_pt_warm_ns = warm_e8.as_nanos() as f64 / N as f64;
        println!(
            "[E8 NSM bench] N={N} \n  \
             COLD: G(E8)={g_e8_cold:.6} G(Z8)={g_z8_cold:.6} ratio={ratio_cold:.4} \
             | decode E8 {cold_e8:?} ({per_pt_cold_ns:.1} ns/pt), Z8 {cold_z8:?}\n  \
             WARM: G(E8)={g_e8_warm:.6} G(Z8)={g_z8_warm:.6} ratio={ratio_warm:.4} \
             ({pct_better:.1}% lower error) | decode E8 {warm_e8:?} \
             ({per_pt_warm_ns:.1} ns/pt), Z8 {warm_z8:?}\n  \
             theoretical: G(E8)={G_E8:.6} G(Z8)={G_Z8:.6} ratio={:.4}",
            G_E8 / G_Z8
        );
        // The measured win must be real and in the expected neighbourhood.
        assert!(ratio_warm < 1.0, "E8 must beat cubic: ratio {ratio_warm}");
        assert!(
            pct_better > 8.0 && pct_better < 20.0,
            "expected ~14% error reduction, measured {pct_better:.1}%"
        );
    }

    #[test]
    fn splitmix_is_deterministic() {
        let mut a = SplitMix64::new(42);
        let mut b = SplitMix64::new(42);
        assert_eq!(a.next_u64(), b.next_u64());
    }
}
